import React, { useState, useEffect, useContext } from "react";
import axios from "axios";
import { VerticalGraph } from "./VerticalGraph";
import SocketContext from "../context/SocketContext";
// import { mockHoldings } from "../data/mockData";

// import { holdings } from "../data/data";

const Holdings = () => {
  const [allHoldings, setAllHoldings] = useState([]);

  useEffect(() => {
    axios
      .get("http://localhost:3002/allHoldings")
      .then((res) => {
        setAllHoldings(res.data);
      })
      .catch((err) => {
        console.warn("Backend unavailable, using mock data:", err.message);
        // setAllHoldings(holdings);
      });
  }, []);

  const socket = useContext(SocketContext);

  useEffect(() => {
    if (!socket) return;

    const handleHoldingsUpdated = (holding) => {
      setAllHoldings((prev) => {
        const found = prev.find((h) => h.name === holding.name || h._id === holding._id);
        if (found) {
          return prev.map((h) => (h.name === holding.name || h._id === holding._id ? holding : h));
        }
        return [holding, ...prev];
      });
    };

    const handlePriceUpdate = ({ name, price }) => {
      setAllHoldings((prev) => prev.map((h) => (h.name === name ? { ...h, price } : h)));
    };

    socket.on("holdingsUpdated", handleHoldingsUpdated);
    socket.on("priceUpdate", handlePriceUpdate);

    return () => {
      socket.off("holdingsUpdated", handleHoldingsUpdated);
      socket.off("priceUpdate", handlePriceUpdate);
    };
  }, [socket]);

  // const labels = ['January', 'February', 'March', 'April', 'May', 'June', 'July'];
  const labels = allHoldings.map((subArray) => subArray["name"]);

  const data = {
    labels,
    datasets: [
      {
        label: "Stock Price",
        data: allHoldings.map((stock) => stock.price),
        backgroundColor: "rgba(255, 99, 132, 0.5)",
      },
    ],
  };

  // export const data = {
  //   labels,
  //   datasets: [
  // {
  //   label: 'Dataset 1',
  //   data: labels.map(() => faker.datatype.number({ min: 0, max: 1000 })),
  //   backgroundColor: 'rgba(255, 99, 132, 0.5)',
  // },
  //     {
  //       label: 'Dataset 2',
  //       data: labels.map(() => faker.datatype.number({ min: 0, max: 1000 })),
  //       backgroundColor: 'rgba(53, 162, 235, 0.5)',
  //     },
  //   ],
  // };

  return (
    <>
      <h3 className="title">Holdings ({allHoldings.length})</h3>

      <div className="order-table table-responsive">
        <table>
          <thead>
            <tr>
              <th>Instrument</th>
              <th>Qty.</th>
              <th>Avg. cost</th>
              <th>LTP</th>
              <th>Cur. val</th>
              <th>P&L</th>
              <th>Net chg.</th>
              <th>Day chg.</th>
            </tr>
          </thead>
          <tbody>
            {allHoldings.map((stock, index) => {
            const curValue = stock.price * stock.qty;
            const isProfit = curValue - stock.avg * stock.qty >= 0.0;
            const profClass = isProfit ? "profit" : "loss";
            const dayClass = stock.isLoss ? "loss" : "profit";

            return (
              <tr key={index}>
                <td data-label="Instrument">{stock.name}</td>
                <td data-label="Qty">{stock.qty}</td>
                <td data-label="Avg. cost">{stock.avg.toFixed(2)}</td>
                <td data-label="LTP">{stock.price.toFixed(2)}</td>
                <td data-label="Cur. val">{curValue.toFixed(2)}</td>
                <td data-label="P&L" className={profClass}>
                  {(curValue - stock.avg * stock.qty).toFixed(2)}
                </td>
                <td data-label="Net chg." className={profClass}>{stock.net}</td>
                <td data-label="Day chg." className={dayClass}>{stock.day}</td>
              </tr>
            );
          })}
          </tbody>
        </table>
      </div>

      <div className="row">
        <div className="col">
          <h5>
            29,875.<span>55</span>{" "}
          </h5>
          <p>Total investment</p>
        </div>
        <div className="col">
          <h5>
            31,428.<span>95</span>{" "}
          </h5>
          <p>Current value</p>
        </div>
        <div className="col">
          <h5>1,553.40 (+5.20%)</h5>
          <p>P&L</p>
        </div>
      </div>
      <VerticalGraph data={data} />
    </>
  );
};

export default Holdings;
